다음 SQL 쿼리의 결과는 무엇인가요?

employees 테이블: id(1,2,3,4), dept('A','A','B','B'), salary(100,200,150,300)

SELECT dept, salary, RANK() OVER (PARTITION BY dept ORDER BY salary DESC) as rnk FROM employees;

code:
SELECT dept, salary,
  RANK() OVER (
    PARTITION BY dept
    ORDER BY salary DESC
  ) as rnk
FROM employees;

