다음 SQL 쿼리의 결과는 무엇인가요?

employees 테이블: id(1,2,3), name('A','B','C'), manager_id(NULL,1,1)

SELECT e.name AS employee, m.name AS manager FROM employees e LEFT JOIN employees m ON e.manager_id = m.id;

code:
SELECT name FROM employees e
WHERE salary > (
  SELECT AVG(salary)
  FROM employees
  WHERE dept = e.dept
);

